solution.code:
fn fibonacci(n: usize) -> Vec<u64> {
    let mut fibs = Vec::new();
    let (mut a, mut b) = (0u64, 1u64);
    for _ in 0..n {
        fibs.push(a);
        let next = a + b;
        a = b;
        b = next;
    }
    fibs
}

fn main() {
    println!("{:?}", fibonacci(8));
}

