solution.code:
use std::collections::BinaryHeap;

fn main() {
    let mut heap = BinaryHeap::new();
    let nums = [4, 1, 7, 3, 9, 2];
    for &n in &nums {
        heap.push(n);
    }
    let mut result = Vec::new();
    while let Some(val) = heap.pop() {
        result.push(val.to_string());
    }
    println!("{}", result.join(" "));
}

