use std::collections::HashSet;

fn find_pairs(nums: &[i32], target: i32) -> Vec<(i32, i32)> {
    let mut seen = HashSet::new();
    let mut used = HashSet::new();
    let mut result = Vec::new();
    for &num in nums {
        let complement = target - num;
        let pair = (num.min(complement), num.max(complement));
        if seen.contains(&complement) && !used.contains(&pair) {
            result.push(pair);
            used.insert(pair);
        }
        seen.insert(num);
    }
    result.sort();
    result
}

