fn find_median_sorted(a: &[i32], b: &[i32]) -> f64 {
    let mut merged = Vec::with_capacity(a.len() + b.len());
    let (mut i, mut j) = (0, 0);
    while i < a.len() && j < b.len() {
        if a[i] <= b[j] {
            merged.push(a[i]);
            i += 1;
        } else {
            merged.push(b[j]);
            j += 1;
        }
    }
    while i < a.len() {
        merged.push(a[i]);
        i += 1;
    }
    while j < b.len() {
        merged.push(b[j]);
        j += 1;
    }
    let n = merged.len();
    if n % 2 == 1 {
        merged[n / 2] as f64
    } else {
        (merged[n / 2 - 1] + merged[n / 2]) as f64 / 2.0
    }
}

