fn has_cycle(adj: &Vec<Vec<usize>>, n: usize) -> bool {
    let mut color = vec![0u8; n];
    for i in 0..n {
        if color[i] == 0 {
            if dfs(adj, i, &mut color) {
                return true;
            }
        }
    }
    false
}

fn dfs(adj: &Vec<Vec<usize>>, node: usize, color: &mut Vec<u8>) -> bool {
    color[node] = 1;
    for &neighbor in &adj[node] {
        if color[neighbor] == 1 {
            return true;
        }
        if color[neighbor] == 0 && dfs(adj, neighbor, color) {
            return true;
        }
    }
    color[node] = 2;
    false
}

