fn evaluate(expr: &str) -> i64 {
    let mut stack: Vec<(i64, i64)> = Vec::new();
    let mut result: i64 = 0;
    let mut sign: i64 = 1;
    let mut num: i64 = 0;
    let chars: Vec<char> = expr.chars().collect();
    let mut i = 0;
    while i < chars.len() {
        let ch = chars[i];
        if ch.is_ascii_digit() {
            num = 0;
            while i < chars.len() && chars[i].is_ascii_digit() {
                num = num * 10 + (chars[i] as i64 - '0' as i64);
                i += 1;
            }
            result += sign * num;
            continue;
        } else if ch == '+' {
            sign = 1;
        } else if ch == '-' {
            sign = -1;
        } else if ch == '(' {
            stack.push((result, sign));
            result = 0;
            sign = 1;
        } else if ch == ')' {
            let (prev_result, prev_sign) = stack.pop().unwrap();
            result = prev_result + prev_sign * result;
        }
        i += 1;
    }
    result
}

fn main() {
    println!("{}", evaluate("3+(2-1)"));
    println!("{}", evaluate("10-(2+3-(1+1))"));
}

