impl User {
    fn serialize(&self) -> String {
        format!("{}:{}:{}", self.name, self.age, self.active)
    }

    fn deserialize(s: &str) -> Option<User> {
        let parts: Vec<&str> = s.split(':').collect();
        if parts.len() != 3 {
            return None;
        }
        let name = parts[0].to_string();
        let age = parts[1].parse::<u32>().ok()?;
        let active = parts[2].parse::<bool>().ok()?;
        Some(User { name, age, active })
    }
}

